def create_secure_server(
    token_validator: TokenValidator,
    port: int = 50051,
    use_tls: bool = True,
    server_cert_path: Optional[str] = None,
    server_key_path: Optional[str] = None,
    ca_cert_path: Optional[str] = None,
    max_workers: int = 10,
) -> grpc.Server:
    """
    Create a secure gRPC server with authentication interceptors.

    Args:
        token_validator: Token validator instance
        port: Port to listen on
        use_tls: Whether to use TLS (strongly recommended for production)
        server_cert_path: Path to server certificate (PEM)
        server_key_path: Path to server private key (PEM)
        ca_cert_path: Path to CA certificate for client cert validation
        max_workers: Maximum number of worker threads
    """
    # Create interceptors
    rate_limiter = RateLimiter(max_attempts=20, window_seconds=60)
    audit_interceptor = AuditLoggingInterceptor()
    auth_interceptor = AuthInterceptor(token_validator, rate_limiter)

    # Interceptors are applied in order: audit first, then auth
    server = grpc.server(
        futures.ThreadPoolExecutor(max_workers=max_workers),
        interceptors=[audit_interceptor, auth_interceptor],
        options=[
            # Limit message sizes to prevent abuse
            ('grpc.max_receive_message_length', 4 * 1024 * 1024),  # 4MB
            ('grpc.max_send_message_length', 4 * 1024 * 1024),     # 4MB
            # Keepalive settings
            ('grpc.keepalive_time_ms', 30000),
            ('grpc.keepalive_timeout_ms', 10000),
            ('grpc.keepalive_permit_without_calls', False),
            ('grpc.http2.max_pings_without_data', 0),
            ('grpc.http2.min_ping_interval_without_data_ms', 300000),
        ],
    )

    if use_tls:
        if not server_cert_path or not server_key_path:
            raise ValueError(
                "TLS is enabled but server_cert_path and server_key_path "
                "are required. Set use_tls=False only for local development."
            )

        with open(server_key_path, 'rb') as f:
            server_key = f.read()
        with open(server_cert_path, 'rb') as f:
            server_cert = f.read()

        ca_cert = None
        if ca_cert_path:
            with open(ca_cert_path, 'rb') as f:
                ca_cert = f.read()

        # Use mutual TLS if CA cert is provided
        if ca_cert:
            server_credentials = grpc.ssl_server_credentials(
                [(server_key, server_cert)],
                root_certificates=ca_cert,
                require_client_auth=True,
            )
        else:
            server_credentials = grpc.ssl_server_credentials(
                [(server_key, server_cert)]
            )

        server.add_secure_port(f'[::]:{port}', server_credentials)
        logger.info("Server configured with TLS on port %d", port)
    else:
        logger.warning(
            "⚠️  Server running WITHOUT TLS on port %d. "
            "This is only acceptable for local development!", port
        )
        server.add_insecure_port(f'[::]:{port}')

    return server


