def main():
    """Start the gRPC server."""
    # Generate a secure signing secret
    # In production, load this from a secure secret manager (e.g., Vault, AWS KMS)
    signing_secret = secrets.token_bytes(64)

    token_validator = TokenValidator(signing_secret)

    # Create example tokens for testing
    user_token = token_validator.create_token(
        subject="user@example.com",
        roles={"user"},
        ttl_seconds=3600,
    )
    admin_token = token_validator.create_token(
        subject="admin@example.com",
        roles={"user", "admin"},
        ttl_seconds=3600,
    )

    logger.info("=" * 60)
    logger.info("Example tokens for testing:")
    logger.info("User token:  %s", user_token)
    logger.info("Admin token: %s", admin_token)
    logger.info("=" * 60)

    # For demonstration, run without TLS
    # In production, ALWAYS use TLS
    server = create_secure_server(
        token_validator=token_validator,
        port=50051,
        use_tls=False,  # Set True in production with proper certs
    )

    logger.info("Starting gRPC server on port 50051...")
    logger.info("Auth policy:")
    logger.info("  /health, /metrics, /healthz, /livez, /readyz -> No auth")
    logger.info("  /admin/*  -> Admin role required (elevated auth)")
    logger.info("  All other -> Standard auth required")
    logger.info("")
    logger.info(
        "⚠️  SECURITY NOTE: Admin endpoints require ELEVATED auth, "
        "they do NOT bypass authentication."
    )

    server.start()

    try:
        server.wait_for_termination()
    except KeyboardInterrupt:
        logger.info("Shutting down server...")
        server.stop(grace=5)


