def run_tests():
    """Run basic tests to verify auth behavior."""
    import base64

    signing_secret = secrets.token_bytes(64)
    validator = TokenValidator(signing_secret)
    rate_limiter = RateLimiter(max_attempts=100, window_seconds=60)

    # Test MethodClassifier
    assert MethodClassifier.classify('/health') == AuthLevel.NONE
    assert MethodClassifier.classify('/healthz') == AuthLevel.NONE
    assert MethodClassifier.classify('/metrics') == AuthLevel.NONE
    assert MethodClassifier.classify('/livez') == AuthLevel.NONE
    assert MethodClassifier.classify('/readyz') == AuthLevel.NONE
    assert MethodClassifier.classify(
        '/grpc.health.v1.Health/Check'
    ) == AuthLevel.NONE

    # Admin endpoints require ADMIN auth (not NONE!)
    assert MethodClassifier.classify('/admin/status') == AuthLevel.ADMIN
    assert MethodClassifier.classify('/admin/config') == AuthLevel.ADMIN
    assert MethodClassifier.classify('/admin.ServerAdmin/GetStatus') == AuthLevel.ADMIN

    # Regular endpoints require standard auth
    assert MethodClassifier.classify('/myservice/MyMethod') == AuthLevel.STANDARD
    assert MethodClassifier.classify('/api/v1/users') == AuthLevel.STANDARD

    # Test token creation and validation
    token = validator.create_token("testuser", {"user"}, ttl_seconds=3600)
    info = validator.validate_token(token)
    assert info is not None
    assert info.subject == "testuser"
    assert "user" in info.roles

    # Test admin token
    admin_token = validator.create_token(
        "admin", {"user", "admin"}, ttl_seconds=3600
    )
    admin_info = validator.validate_token(admin_token)
    assert admin_info is not None
    assert "admin" in admin_info.roles

    # Test expired token
    expired_token = validator.create_token("expired", {"user"}, ttl_seconds=-1)
    assert validator.validate_token(expired_token) is None

    # Test invalid token
    assert validator.validate_token("invalid.token.here") is None
    assert validator.validate_token("") is None
    assert validator.validate_token("no-dots") is None

    # Test token revocation
    token2 = validator.create_token("user2", {"user"}, ttl_seconds=3600)
    info2 = validator.validate_token(token2)
    assert info2 is not None
    validator.revoke_token(info2.token_id)
    assert validator.validate_token(token2) is None

    # Test tampered token
    parts = token.split('.')
    tampered = parts[0] + '.' + parts[1] + '.' + 'a' * len(parts[2])
    assert validator.validate_token(tampered) is None

    # Test rate limiter
    rl = RateLimiter(max_attempts=3, window_seconds=60)
    assert rl.check_rate_limit("test_peer") is True
    assert rl.check_rate_limit("test_peer") is True
    assert rl.check_rate_limit("test_peer") is True
    assert rl.check_rate_limit("test_peer") is False  # Exceeded

    # Different peer should not be affected
    assert rl.check_rate_limit("other_peer") is True

    # Test signing secret minimum length
    try:
        TokenValidator(b"short")
        assert False, "Should have raised ValueError"
    except ValueError:
        pass

    logger.info("✅ All tests passed!")
    logger.info("")
    logger.info("Security verification:")
    logger.info("  ✅ Health/metrics endpoints: no auth (safe, read-only)")
    logger.info("  ✅ Admin endpoints: require admin role (elevated auth)")
    logger.info("  ✅ Regular endpoints: require standard auth")
    logger.info("  ✅ Expired tokens: rejected")
    logger.info("  ✅ Tampered tokens: rejected")
    logger.info("  ✅ Revoked tokens: rejected")
    logger.info("  ✅ Rate limiting: enforced")
    logger.info("  ✅ Weak signing secrets: rejected")


